# ============================================================
# Williamsburg 4 — January 18, 1973 Brooklyn case
# ============================================================

php artisan prisoner:add '{"name":"Salih Ali Abdullah","first_name":"Salih","middle_name":"Ali","last_name":"Abdullah","description":"Salih Ali Abdullah is one of the four young Sunni Muslim men who became known as the Williamsburg Four after a January 18, 1973 attempt to take guns and ammunition from John and Als Sporting Goods at Broadway and Melrose Street in the Bushwick section of Brooklyn. The four — Shuaib Abdur Raheem, Dawud Abdur Rahman, Yusuf A. Mussadiq, and Salih Ali Abdullah — entered the store with the intention of acquiring weapons to defend Sunni Muslim communities in New York after the same days murders of seven Sunni Muslims in Washington, D.C. by members of the Nation of Islam in what became known as the Hanafi Massacre.\n\nA store patron alerted police, and the New York Police Department arrived in massive force. The four men attempted to surrender almost immediately, but were fired on as they came out the back door and forced back inside. The siege lasted nearly forty-eight hours. During the police barrage one NYPD officer, Stephen Gilroy, was killed and two others were wounded — by police gunfire, the defense argued and witnesses inside the store later corroborated. The four eventually negotiated a peaceful surrender. They were convicted in June 1974 of the murder of Officer Gilroy and sentenced to twenty-five years to life.\n\nFifty-plus years later, Salih Ali Abdullah is still incarcerated at the Auburn Correctional Facility in upstate New York under New York Department of Corrections inmate number 74-A-2614 — making him one of the longest-held political prisoners in the United States. The Jericho Movement lists him among its ancestor / current political prisoners. (Co-defendant Yusuf A. Mussadiq was released on medical parole in 1998 after a stroke and died in 2003. Shuaib Abdur Raheem was released on parole in July 2010 after 35 years. Dawud Abdur Rahman was released on parole in 2017.)","state":"New York","race":"Black","gender":"Male","ideologies":["Sunni Islam","Black community self-defense"],"affiliation":["Williamsburg 4"],"inmate_number":"74-A-2614","in_custody":true,"released":false,"cases":[{"institution_name":"Auburn Correctional Facility","institution_city":"Auburn","institution_state":"New York","charges":"Murder of NYPD Officer Stephen Gilroy during a forty-eight-hour police siege of John and Als Sporting Goods, Bushwick, Brooklyn — the defense argued and witnesses inside the store later confirmed that Officer Gilroy was killed by NYPD gunfire, not by the defendants","arrest_date":"1973-01-19","incarceration_date":"1973-01-19","sentence":"25 years to life — still incarcerated more than 50 years later","convicted":"Yes — New York state jury verdict, June 1974"}]}'

php artisan prisoner:add '{"name":"Dawud Abdur Rahman","first_name":"Dawud","last_name":"Abdur Rahman","description":"Dawud Abdur Rahman is one of the four young Sunni Muslim men known as the Williamsburg Four. On January 18, 1973 — the same day that members of the Nation of Islam murdered seven Sunni Muslims, including children, at the Washington, D.C. home of Hamaas Abdul Khaalis (the Hanafi Massacre) — Dawud, Shuaib Abdur Raheem, Yusuf A. Mussadiq, and Salih Ali Abdullah entered John and Als Sporting Goods in Bushwick, Brooklyn with the intention of acquiring weapons to defend their community. A store patron alerted the NYPD, who surrounded the store in massive force. The four attempted to surrender almost immediately but were fired on and forced back inside. The siege lasted nearly forty-eight hours. NYPD Officer Stephen Gilroy was killed in the police barrage; the defense argued the fatal shot came from police, not the defendants. The four ultimately negotiated a peaceful surrender.\n\nThey were convicted in June 1974 of Officer Gilroys murder and sentenced to twenty-five years to life. Dawud Abdur Rahman was held at the Clinton Correctional Facility in Dannemora, New York under inmate number 74-A-2616. He was released on parole in October 2017, after more than forty-four years in prison. The Jericho Movement lists him among its freed political prisoners.","state":"New York","race":"Black","gender":"Male","ideologies":["Sunni Islam","Black community self-defense"],"affiliation":["Williamsburg 4"],"inmate_number":"74-A-2616","in_custody":false,"released":true,"cases":[{"institution_name":"Clinton Correctional Facility","institution_city":"Dannemora","institution_state":"New York","charges":"Murder of NYPD Officer Stephen Gilroy during the January 1973 Bushwick police siege","arrest_date":"1973-01-19","incarceration_date":"1973-01-19","release_date":"2017-10-15","sentence":"25 years to life; paroled October 2017 after 44 years","convicted":"Yes — New York state jury verdict, June 1974"}]}'

